<template><section class="panel"><canvas ref="canvasEl"></canvas><pre data-testid="game-state" class="sr-only">{{ stateText }}</pre><p>方向键移动，闭合路径会自动占领区域。</p></section></template><script setup lang="ts">import { computed, onMounted, ref, watchEffect } from 'vue'; import { useGameStore } from '../../stores/gameStore'; import { renderMap } from '../../utils/mapRenderer'; import { useKeyboard } from '../../hooks/useKeyboard'; import { useGameLoop } from '../../hooks/useGameLoop'; const canvasEl=ref<HTMLCanvasElement>(); const store=useGameStore(); const stateText=computed(()=>JSON.stringify({origin:'top-left x-right y-down',tick:store.state?.tick,player:store.state?.players[0],leaderboards:store.state?.leaderboards})); useKeyboard(); useGameLoop(); onMounted(()=>{ if(!store.state) store.start('demo-room'); }); watchEffect(()=>{ if(canvasEl.value && store.state) renderMap(canvasEl.value, store.state); window.__territoryrush_snapshot=stateText.value; window.render_game_to_text=()=>window.__territoryrush_snapshot || '{}'; });</script><style scoped>canvas{width:100%;max-width:720px;border:1px solid #b8d7e8}.sr-only{position:absolute;width:1px;height:1px;overflow:hidden;clip:rect(0,0,0,0)}</style>
